parameters.jsonSchema:
{
  "type": "object",
  "required": [
    "label",
    "is_customer",
    "customer_intent",
    "confidence_score",
    "sentiment",
    "order_number",
    "customer_name",
    "request_details"
  ],
  "properties": {
    "label": {
      "type": "string",
      "enum": ["Escalated to Bot", "Notification", "Escalated to CS"],
      "description": "Classification label indicating how the message should be handled."
    },
    "is_customer": {
      "type": "boolean",
      "description": "Indicates whether the message is from a customer."
    },
    "customer_intent": {
      "type": "string",
      "enum": [
        "Order Status Inquiry",
        "Shipping Issue",
        "Complaint",
        "Refund Request",
        "Product Inquiry",
        "Change Request",
        "Change Address Shipping",
        "Incorrect Order Information"
      ],
      "description": "Categorized intent of the customer message."
    },
    "confidence_score": {
      "type": "number",
      "minimum": 0,
      "maximum": 1,
      "description": "Confidence score of the classification (0 to 1)."
    },
    "sentiment": {
      "type": "string",
      "enum": ["Positive", "Neutral", "Negative"],
      "description": "Detected sentiment of the message."
    },
    "order_number": {
      "type": ["string", "null"],
      "pattern": "^#BCMC\\d{6}$",
      "description": "Order number in format #BCMC followed by 6 digits, or null if not available."
    },
    "customer_name": {
      "type": ["string", "null"],
      "description": "Customer name if available, otherwise null."
    },
    "request_details": {
      "type": "string",
      "description": "Detailed explanation of the customer's request."
    },"number_token": {
      "type": "number"
    }
  },
  "additionalProperties": false
}

