parameters.inputSchema:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "type": "object",
  "required": [
    "completed",
    "summary",
    "label",
    "intent",
    "order_id",
    "tracking_number",
    "customer_tone",
    "is_customer",
    "customer_intent",
    "confidence_score",
    "sentiment",
    "order_number",
    "customer_name",
    "request_details",
    "urgency",
    "entities"
  ],
  "properties": {
    "completed": {
      "type": "boolean",
      "description": "Whether the issue is resolved or the conversation is complete"
    },
    "summary": {
      "type": "string",
      "minLength": 5
    },
    "label": {
      "type": "string",
      "enum": ["Escalated to CS", "Escalated to Bot", "Notification"]
    },
    "intent": {
      "type": "string"
    },
    "customer_tone": {
      "type": "string",
      "enum": ["polite", "neutral", "angry", "frustrated", "urgent"]
    },
    "is_customer": {
      "type": "boolean"
    },
    "customer_intent": {
      "type": "string"
    },
    "confidence_score": {
      "type": "number",
      "minimum": 0,
      "maximum": 1
    },
    "sentiment": {
      "type": "string",
      "enum": ["Positive", "Neutral", "Negative"]
    },
    "order_number": {
      "type": ["string", "null"],
      "pattern": "^#BCMC[0-9]{6}$"
    },
    "customer_name": {
      "type": ["string", "null"]
    },
    "request_details": {
      "type": "string"
    },
    "urgency": {
      "type": "string",
      "enum": ["low", "medium", "high"]
    },
    "entities": {
      "type": "object",
      "required": ["product", "issue", "dates", "location"],
      "properties": {
        "product": {
          "type": ["string", "null"]
        },
        "issue": {
          "type": ["string", "null"]
        },
        "dates": {
          "type": ["string", "null"]
        },
        "location": {
          "type": ["string", "null"]
        }
      },
      "additionalProperties": false
    }
  },
  "additionalProperties": false
}

